import java.util.zip.ZipFile;
import java.util.zip.ZipOutputStream;

import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

public class ParseBenchmarkTest {

  private static File testZipFile;

  @BeforeAll
  static void createTestZip() throws Exception {
    // Create a temporary zip file with a known entry
    testZipFile = File.createTempFile("ParseBenchmarkData", ".zip");
    try (ZipOutputStream zos = new ZipOutputStream(new FileOutputStream(testZipFile))) {
      ZipEntry entry = new ZipEntry("testfile.txt");
      zos.putNextEntry(entry);
      String content = "Hello, world!";
      zos.write(content.getBytes(StandardCharsets.UTF_8));
      zos.closeEntry();
    }
  }

  @AfterAll
  static void cleanup() {
    if (testZipFile != null && testZipFile.exists()) {
      testZipFile.delete();
    }
  }

  /**
   * Use reflection to invoke the private static method 'resourceToString' of ParseBenchmark,
   * but temporarily replace the private static method 'getResourceFile' to return our test zip file.
   */
  private static String invokeResourceToString(String fileName) throws Exception {
    // Use reflection to get the private static resourceToString method
    Method resourceToStringMethod = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
    resourceToStringMethod.setAccessible(true);

    // Use reflection to replace getResourceFile temporarily by a dynamic proxy or similar is not possible,
    // so instead we use reflection to replace the private static getResourceFile method by reflection is not possible either.
    // Therefore, we simulate by temporarily renaming the test zip file to the expected resource path location in the classpath,
    // but since this is complicated, we instead create a helper method that calls resourceToString but replaces the resource file.

    // Alternative: use reflection to invoke getResourceFile and replace the returned file by a proxy is impossible.
    // So we hack by temporarily replacing the resource file by a symlink or system property is also complicated.

    // The simplest approach: use reflection to call resourceToString, but before that,
    // we temporarily replace the file returned by getResourceFile by renaming testZipFile to the expected file path.
    // But since the method getResourceFile is private static, we cannot override it.

    // Therefore, instead, we invoke resourceToString with the fileName, but before that,
    // we replace the resource file on disk by copying testZipFile to the expected location.

    // Let's find out what getResourceFile("/ParseBenchmarkData.zip") returns:
    Method getResourceFileMethod = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
    getResourceFileMethod.setAccessible(true);
    File originalFile = (File) getResourceFileMethod.invoke(null, "/ParseBenchmarkData.zip");

    // Backup original file if exists
    File backupFile = null;
    if (originalFile != null && originalFile.exists()) {
      backupFile = new File(originalFile.getAbsolutePath() + ".bak");
      if (!originalFile.renameTo(backupFile)) {
        throw new IllegalStateException("Cannot backup original resource file");
      }
    }

    // Copy testZipFile to originalFile location
    if (originalFile != null) {
      java.nio.file.Files.copy(testZipFile.toPath(), originalFile.toPath(), java.nio.file.StandardCopyOption.REPLACE_EXISTING);
    }

    try {
      return (String) resourceToStringMethod.invoke(null, fileName);
    } catch (InvocationTargetException e) {
      // unwrap
      throw (e.getCause() != null) ? (Exception) e.getCause() : e;
    } finally {
      // Restore original file
      if (backupFile != null && backupFile.exists()) {
        if (!backupFile.renameTo(originalFile)) {
          throw new IllegalStateException("Cannot restore original resource file");
        }
      }
    }
  }

  @Test
  void testResourceToString_readsContentCorrectly() throws Exception {
    String content = invokeResourceToString("testfile.txt");
    assertEquals("Hello, world!", content);
  }

  @Test
  void testResourceToString_fileNotFound_throwsException() throws Exception {
    Exception ex = assertThrows(IllegalArgumentException.class, () -> {
      invokeResourceToString("nonexistent.txt");
    });
    assertEquals("File not found in zip: nonexistent.txt", ex.getMessage());
  }

  @Test
  void testResourceToString_nullFileName_throwsNullPointerException() throws Exception {
    assertThrows(NullPointerException.class, () -> {
      invokeResourceToString(null);
    });
  }
}
